import UIKit
import Foundation

// Enum for transaction types
enum TransactionType {
    case buy
    case sell
}

class Stock {
    var symbol: String
    var name: String
    var currentPrice: Double
    
    init(symbol: String, name: String, currentPrice: Double) {
        self.symbol = symbol
        self.name = name
        self.currentPrice = currentPrice
    }
}

class Portfolio {
    var stocks: [Stock] = []
    
    func addStock(stock: Stock) {
        stocks.append(stock)
    }
    
    func removeStock(stock: Stock) {
        if let index = stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            stocks.remove(at: index)
        }
    }
}

class TradeExecutor {
    var portfolio: Portfolio
    
    init(portfolio: Portfolio) {
        self.portfolio = portfolio
    }
    
    func executeTrade(transactionType: TransactionType, stock: Stock, quantity: Int) {
        switch transactionType {
        case .buy:
            addStockToPortfolio(stock: stock, quantity: quantity)
        case .sell:
            removeStockFromPortfolio(stock: stock, quantity: quantity)
        }
        
        saveTransactions()
    }
    
    func addStockToPortfolio(stock: Stock, quantity: Int) {
        let existingStock = portfolio.stocks.first { $0.symbol == stock.symbol }
        
        if let existingStock = existingStock {
            var updatedQuantity = existingStock.currentPrice * Double(quantity)
            let newStock = Stock(symbol: stock.symbol, name: stock.name, currentPrice: stock.currentPrice)
            
            portfolio.removeStock(stock: newStock)
            portfolio.addStock(stock: newStock)
            saveTransactions()
        } else {
            let newStock = Stock(symbol: stock.symbol, name: stock.name, currentPrice: stock.currentPrice)
            newStock.currentPrice *= Double(quantity)
            
            portfolio.addStock(stock: newStock)
            saveTransactions()
        }
    }
    
    func removeStockFromPortfolio(stock: Stock, quantity: Int) {
        if let index = portfolio.stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            var updatedQuantity = portfolio.stocks[index].currentPrice * Double(quantity)
            
            portfolio.removeStock(stock: portfolio.stocks[index])
            saveTransactions()
        }
    }
    
    func saveTransactions() {
        // Save transactions to database or API
    }
}

class TradingAPI {
    func fetchStocks(completionHandler: @escaping ([Stock]) -> Void) {
        // Fetch stocks from API and pass them back to the caller
        let stocks = [
            Stock(symbol: "AAPL", name: "Apple Inc.", currentPrice: 150.0),
            Stock(symbol: "GOOG", name: "Alphabet Inc.", currentPrice: 2000.0)
        ]
        
        completionHandler(stocks)
    }
}

class TradingViewController: UIViewController {
    let tradeExecutor = TradeExecutor(portfolio: Portfolio())
    var stocks: [Stock] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Fetch stocks from API
        let api = TradingAPI()
        api.fetchStocks { (stocks) in
            self.stocks = stocks
            
            for stock in self.stocks {
                print("\(stock.symbol): \(stock.name) - Current Price: $\(stock.currentPrice)")
                
                // Add a button to execute trade
                let buyButton = UIButton(frame: CGRect(x: 0, y: 0, width: 200, height: 50))
                buyButton.setTitle("Buy", for: .normal)
                buyButton.addTarget(self, action: #selector(buyStock(_:)), for: .touchUpInside)
                
                self.view.addSubview(buyButton)
            }
        }
    }
    
    @objc func buyStock(_ sender: UIButton) {
        guard let stockIndex = stocks.firstIndex(where: { $0.symbol == (sender.titleLabel?.text ?? "") }) else { return }
        
        let quantity = 10
        tradeExecutor.executeTrade(transactionType: .buy, stock: stocks[stockIndex], quantity: quantity)
    }
}